const rootElement=document.documentElement;const darkModeClassName="dark";const darkModeStorageKey="user-color-scheme";const darkModeTimeKey="user-color-scheme-time";const validColorModeKeys={dark:true,light:true};const invertDarkModeObj={dark:"light",light:"dark"};const setLocalStorage=(key,value)=>{try{localStorage.setItem(key,value)}catch(e){}};const removeLocalStorage=key=>{try{localStorage.removeItem(key)}catch(e){}};const getLocalStorage=key=>{try{return localStorage.getItem(key)}catch(e){return null}};const getModeFromCSSMediaQuery=()=>window.matchMedia("(prefers-color-scheme: dark)").matches?"dark":"light";const resetRootDarkModeClassAndLocalStorage=()=>{rootElement.classList.remove(darkModeClassName);rootElement.classList.remove(invertDarkModeObj[darkModeClassName]);removeLocalStorage(darkModeStorageKey)};const applyCustomDarkModeSettings=mode=>{const currentSetting=mode||getLocalStorage(darkModeStorageKey);if(validColorModeKeys[currentSetting]){rootElement.classList.add(currentSetting);rootElement.classList.remove(invertDarkModeObj[currentSetting])}else{resetRootDarkModeClassAndLocalStorage()}};const toggleCustomDarkMode=()=>{let currentSetting=getLocalStorage(darkModeStorageKey);if(validColorModeKeys[currentSetting]){currentSetting=invertDarkModeObj[currentSetting]}else if(currentSetting===null){currentSetting=darkModeClassName}else{return}setLocalStorage(darkModeStorageKey,currentSetting);setLocalStorage(darkModeTimeKey,+new Date);return currentSetting};const initDarkMode=()=>{const savedMode=getLocalStorage(darkModeStorageKey);if(validColorModeKeys[savedMode]){applyCustomDarkModeSettings(savedMode)}else{applyCustomDarkModeSettings("light");setLocalStorage(darkModeStorageKey,"light")}};initDarkMode();